LOG_DIR = "/var/log/application/"


def ensure_log_directory(log_dir):
    """Ensure the log directory exists with proper permissions."""
    try:
        os.makedirs(log_dir, mode=0o755, exist_ok=True)
    except PermissionError:
        fallback_dir = os.path.join(os.path.expanduser("~"), "logs", "application")
        os.makedirs(fallback_dir, mode=0o755, exist_ok=True)
        print(f"Warning: Cannot create {log_dir}, falling back to {fallback_dir}")
        return fallback_dir
    return log_dir


class JSONFormatter(logging.Formatter):
    """Custom JSON formatter for structured logging in production."""

    def format(self, record):
        log_entry = {
            "timestamp": self.formatTime(record, self.datefmt),
            "level": record.levelname,
            "logger": record.name,
            "module": record.module,
            "function": record.funcName,
            "line": record.lineno,
            "message": record.getMessage(),
            "process_id": record.process,
            "thread_id": record.thread,
            "thread_name": record.threadName,
        }

        if record.exc_info and record.exc_info[0] is not None:
            log_entry["exception"] = {
                "type": record.exc_info[0].__name__,
                "message": str(record.exc_info[1]),
                "traceback": self.formatException(record.exc_info),
            }

        if hasattr(record, "request_id"):
            log_entry["request_id"] = record.request_id

        if hasattr(record, "user_id"):
            log_entry["user_id"] = record.user_id

        if hasattr(record, "extra_data"):
            log_entry["extra_data"] = record.extra_data

        return json.dumps(log_entry, default=str)


class ProductionFormatter(logging.Formatter):
    """Detailed formatter for human-readable production logs."""

    def __init__(self):
        fmt = (
            "%(asctime)s | %(levelname)-8s | %(name)s | %(module)s:%(funcName)s:%(lineno)d | "
            "PID:%(process)d | TID:%(thread)d | %(message)s"
        )
        datefmt = "%Y-%m-%d %H:%M:%S"
        super().__init__(fmt=fmt, datefmt=datefmt)


