class ContextLogger:
    """A logger wrapper that supports adding context to log messages."""

    def __init__(self, logger_name, default_context=None):
        self.logger = logging.getLogger(logger_name)
        self.default_context = default_context or {}

    def _log(self, level, message, *args, **kwargs):
        extra = {**self.default_context}
        if "extra" in kwargs:
            extra.update(kwargs.pop("extra"))

        # Create a LogRecord with extra attributes
        kwargs["extra"] = extra
        kwargs.setdefault("stacklevel", 2)
        getattr(self.logger, level)(message, *args, **kwargs)

    def debug(self, message, *args, **kwargs):
        self._log("debug", message, *args, **kwargs)

    def info(self, message, *args, **kwargs):
        self._log("info", message, *args, **kwargs)

    def warning(self, message, *args, **kwargs):
        self._log("warning", message, *args, **kwargs)

    def error(self, message, *args, **kwargs):
        self._log("error", message, *args, **kwargs)

    def critical(self, message, *args, **kwargs):
        self._log("critical", message, *args, **kwargs)

    def exception(self, message, *args, **kwargs):
        kwargs["exc_info"] = True
        self._log("error", message, *args, **kwargs)

    def with_context(self, **context):
        """Return a new ContextLogger with additional context."""
        new_context = {**self.default_context, **context}
        return ContextLogger(self.logger.name, new_context)


def get_logger(name, **default_context):
    """Get a ContextLogger instance for the given name."""
    return ContextLogger(name, default_context)


